SELECT r.*, rep.writer_nm AS parent_comment_nm, mem.member_nm AS writer_id_nm, ste.site_nm AS site_nm, cd_cs.code_label AS comment_status_cd_nm FROM cm_bltn_reply r LEFT JOIN cm_bltn_reply rep ON rep.comment_id = r.parent_comment_id LEFT JOIN mb_member mem ON mem.member_id = r.writer_id LEFT JOIN sy_site ste ON ste.site_id = r.site_id LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'COMMENT_STATUS' AND cd_cs.code_value = r.comment_status_cd
ORDER BY r.comment_id ASC ORDER BY r.comment_id DESC ORDER BY r.writer_nm ASC ORDER BY r.writer_nm DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT r.*, rep.writer_nm AS parent_comment_nm, mem.member_nm AS writer_id_nm, ste.site_nm AS site_nm, cd_cs.code_label AS comment_status_cd_nm FROM cm_bltn_reply r LEFT JOIN cm_bltn_reply rep ON rep.comment_id = r.parent_comment_id LEFT JOIN mb_member mem ON mem.member_id = r.writer_id LEFT JOIN sy_site ste ON ste.site_id = r.site_id LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'COMMENT_STATUS' AND cd_cs.code_value = r.comment_status_cd
ORDER BY r.comment_id ASC ORDER BY r.comment_id DESC ORDER BY r.writer_nm ASC ORDER BY r.writer_nm DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

