UPDATE cm_bltn_reply
site_id = #{siteId}, blog_id = #{blogId}, parent_comment_id = #{parentCommentId}, writer_id = #{writerId}, writer_nm = #{writerNm}, blog_comment_content = #{blogCommentContent}, comment_status_cd = #{commentStatusCd}, comment_status_cd_before = #{commentStatusCdBefore}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE comment_id = #{commentId}
